import React from "react";
import { Route, Routes, Navigate } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import ErrorBoundary from "./components/ErrorBoundary";
import Dashboard from "./pages/Dashboard";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Landing from "./pages/Landing";
import IncidentList from "./pages/IncidentList";
import SecurityTraining from "./pages/SecurityTraining";
import { logoutUser } from "./store/authActions";

// PrivateRoute component to protect routes
const PrivateRoute = ({ children }) => {
  const isAuthenticated = useSelector((state) => state.auth.isAuthenticated);

  // Check localStorage as backup
  const token = localStorage.getItem("access_token");

  if (!isAuthenticated && !token) {
    return <Navigate to="/login" replace />;
  }

  return children;
};

// Logout component
const LogoutButton = () => {
  const dispatch = useDispatch();

  const handleLogout = () => {
    localStorage.removeItem("access_token");
    localStorage.removeItem("refresh_token");
    dispatch(logoutUser());
  };

  return (
    <button onClick={handleLogout} style={{ marginLeft: "auto", background: "#e74c3c", color: "white", border: "none", padding: "8px 16px", borderRadius: "4px", cursor: "pointer" }}>
      Logout
    </button>
  );
};

function App() {
  const isAuthenticated = useSelector((state) => state.auth.isAuthenticated);
  const token = localStorage.getItem("access_token");
  const isLoggedIn = isAuthenticated || token;

  return (
    <div className="App">
      <ErrorBoundary>
        {isLoggedIn && (
          <nav style={{ display: "flex", padding: "10px", background: "#1a1a2e", color: "white" }}>
            <a href="/" style={{ marginRight: "15px", color: "white", textDecoration: "none" }}>Dashboard</a>
            <a href="/incidents" style={{ marginRight: "15px", color: "white", textDecoration: "none" }}>Incidents</a>
            <a href="/training" style={{ marginRight: "15px", color: "white", textDecoration: "none" }}>Training</a>
            <LogoutButton />
          </nav>
        )}
        <Routes>
          <Route path="/" element={isLoggedIn ? <Navigate to="/dashboard" /> : <Landing />} />
          <Route path="/landing" element={isLoggedIn ? <Navigate to="/dashboard" /> : <Landing />} />
          <Route path="/login" element={isLoggedIn ? <Navigate to="/dashboard" /> : <Login />} />
          <Route path="/register" element={isLoggedIn ? <Navigate to="/dashboard" /> : <Register />} />
          <Route
            path="/dashboard"
            element={
              <PrivateRoute>
                <Dashboard />
              </PrivateRoute>
            }
          />
          <Route
            path="/incidents"
            element={
              <PrivateRoute>
                <IncidentList />
              </PrivateRoute>
            }
          />
          <Route
            path="/training"
            element={
              <PrivateRoute>
                <SecurityTraining />
              </PrivateRoute>
            }
          />
        </Routes>
      </ErrorBoundary>
    </div>
  );
}

export default App;
